282→// --- Group 4: Conditional Routes ---
283→
284→func TestConditionalRoutes(t *testing.T) {
285→	t.Parallel()
286→
287→	tests := []struct {
288→		name       string
289→		cfgFn      func(*config.Config)
290→		method     string
291→		path       string
292→		wantExists bool // true = expect non-404, false = expect 404/405
293→	}{
294→		{
295→			name:       "dev auth login exists in development",
296→			cfgFn:      func(c *config.Config) { c.Env = "development"; c.JWTSecret = "dev" },
297→			method:     "POST",
298→			path:       "/dev/auth/login",
299→			wantExists: true,
300→		},
301→		{
302→			name:       "dev auth login absent in production",
303→			cfgFn:      func(c *config.Config) { c.Env = "production" },
304→			method:     "POST",
305→			path:       "/dev/auth/login",
306→			wantExists: false,
307→		},
308→		{
309→			name:       "playground exists when enabled",
310→			cfgFn:      func(c *config.Config) { c.GraphQLPlayground = true },
311→			method:     "GET",
312→			path:       "/playground",
313→			wantExists: true,
314→		},
315→		{
316→			name:       "playground absent when disabled",
317→			cfgFn:      func(c *config.Config) { c.GraphQLPlayground = false },
318→			method:     "GET",
319→			path:       "/playground",
320→			wantExists: false,
321→		},
322→		{
323→			name:       "mcp absent when disabled",
324→			cfgFn:      func(c *config.Config) { c.MCPEnabled = false },
325→			method:     "POST",
326→			path:       "/mcp/message",
327→			wantExists: false,
328→		},
329→		{
330→			name:       "mcp exists when enabled",
331→			cfgFn:      func(c *config.Config) { c.MCPEnabled = true },
332→			method:     "POST",
333→			path:       "/mcp/message",
334→			wantExists: true,
335→		},
336→	}
337→	for _, tt := range tests {
338→		t.Run(tt.name, func(t *testing.T) {
339→			t.Parallel()
340→			cfg := testConfig(tt.cfgFn)
341→			h := router.New(testDeps(cfg, &stubValidator{}))
342→
343→			req := httptest.NewRequest(tt.method, tt.path, nil)
344→			rr := httptest.NewRecorder()
345→			h.ServeHTTP(rr, req)
346→
347→			is404 := rr.Code == http.StatusNotFound || rr.Code == http.StatusMethodNotAllowed
348→			if tt.wantExists && is404 {
349→				t.Errorf("route %s %s: status = %d, expected route to exist", tt.method, tt.path, rr.Code)
350→			}
351→			if !tt.wantExists && !is404 {
352→				t.Errorf("route %s %s: status = %d, expected 404/405", tt.method, tt.path, rr.Code)
353→			}
354→		})
355→	}
356→}
