377→// --- Group 6: Private Route IP Restriction ---
378→
379→func TestPrivateRouteIPRestriction(t *testing.T) {
380→	t.Parallel()
381→
382→	_, cidr, err := net.ParseCIDR("10.0.0.0/8")
383→	if err != nil {
384→		t.Fatalf("parse CIDR: %v", err)
385→	}
386→
387→	cfg := testConfig()
388→	deps := testDeps(cfg, &stubValidator{})
389→	deps.PrivateCIDRs = []*net.IPNet{cidr}
390→	h := router.New(deps)
391→
392→	tests := []struct {
393→		name       string
394→		remoteAddr string
395→		wantStatus int
396→	}{
397→		{
398→			name:       "allowed IP passes through",
399→			remoteAddr: "10.1.2.3:12345",
400→			wantStatus: 0, // not 403 (handler may return 500 due to nil DB, that's fine)
401→		},
402→		{
403→			name:       "denied IP gets 403",
404→			remoteAddr: "192.168.1.1:12345",
405→			wantStatus: http.StatusForbidden,
406→		},
407→	}
408→	for _, tt := range tests {
409→		t.Run(tt.name, func(t *testing.T) {
410→			t.Parallel()
411→			req := httptest.NewRequest("GET", "/private/healthcheck", nil)
412→			req.RemoteAddr = tt.remoteAddr
413→			rr := httptest.NewRecorder()
414→			h.ServeHTTP(rr, req)
415→
416→			if tt.wantStatus != 0 && rr.Code != tt.wantStatus {
417→				t.Errorf("status = %d, want %d", rr.Code, tt.wantStatus)
418→			}
419→			if tt.wantStatus == 0 && rr.Code == http.StatusForbidden {
420→				t.Errorf("status = %d, expected non-403 for allowed IP", rr.Code)
421→			}
422→		})
423→	}
424→}
