 18→// ExportCSV returns an HTTP handler that streams search results as a CSV file.
 19→// It reads filter, sort, and user-location parameters from the query string,
 20→// builds a search query capped at maxRows, and writes the results as CSV.
 21→func ExportCSV(pool *pgxpool.Pool, reg *search.Registry, maxRows int) http.HandlerFunc {
 22→	return func(w http.ResponseWriter, r *http.Request) {
 23→		q := r.URL.Query()
 24→
 25→		// Parse filters from query param.
 26→		var filters []search.FilterInput
 27→		if filtersParam := q.Get("filters"); filtersParam != "" {
 28→			if err := json.Unmarshal([]byte(filtersParam), &filters); err != nil {
 29→				writeJSONError(w, http.StatusBadRequest,
 30→					fmt.Sprintf("handler: invalid filters JSON: %v", err))
 31→				return
 32→			}
 33→		}
 34→
 35→		req := search.SearchRequest{
 36→			Filters: filters,
 37→			Limit:   maxRows, // request the maximum; BuildExportQuery caps it
 38→		}
 39→
 40→		// Parse sort.
 41→		if sortParam := q.Get("sort"); sortParam != "" {
 42→			req.Sort = &search.SortInput{
 43→				Field:     sortParam,
 44→				Direction: search.SortDirectionAsc,
 45→			}
 46→			if dirParam := q.Get("sortDir"); dirParam == "DESC" {
 47→				req.Sort.Direction = search.SortDirectionDesc
 48→			}
 49→		}
 50→
 51→		// Parse user location.
 52→		latStr, lngStr := q.Get("userLat"), q.Get("userLng")
 53→		if latStr != "" && lngStr != "" {
 54→			lat, errLat := strconv.ParseFloat(latStr, 64)
 55→			lng, errLng := strconv.ParseFloat(lngStr, 64)
 56→			if errLat != nil || errLng != nil {
 57→				writeJSONError(w, http.StatusBadRequest, "handler: invalid userLat/userLng")
 58→				return
 59→			}
 60→			req.UserLocation = &search.UserLocation{
 61→				Latitude:  lat,
 62→				Longitude: lng,
 63→			}
 64→			if stateParam := q.Get("userState"); stateParam != "" {
 65→				req.UserLocation.State = stateParam
 66→			}
 67→		}
 68→
 69→		// Validate the request using the caller's real auth state.
 70→		authenticated := auth.GetClaims(r.Context()) != nil
 71→		if errs := search.ValidateRequest(reg, req, authenticated); len(errs) > 0 {
 72→			body, _ := json.Marshal(map[string]any{"errors": errs})
 73→			w.Header().Set("Content-Type", "application/json")
 74→			w.WriteHeader(http.StatusBadRequest)
 75→			_, _ = w.Write(body)
 76→			return
 77→		}
 78→
 79→		// Build and execute the export query.
 80→		sqlStr, args, err := search.BuildExportQuery(reg, req, maxRows)
 81→		if err != nil {
 82→			slog.ErrorContext(r.Context(), "handler: build export query", "error", err)
 83→			writeJSONError(w, http.StatusInternalServerError, "handler: failed to build query")
 84→			return
 85→		}
 86→
 87→		rows, err := pool.Query(r.Context(), sqlStr, args...)
 88→		if err != nil {
 89→			slog.ErrorContext(r.Context(), "handler: export query", "error", err)
 90→			writeJSONError(w, http.StatusInternalServerError, "handler: query failed")
 91→			return
 92→		}
 93→		defer rows.Close()
 94→
 95→		// Get exportable field descriptors for CSV columns.
 96→		descriptors := reg.ExportableDescriptors()
 97→
 98→		// Build CSV header row from descriptor labels.
 99→		header := make([]string, len(descriptors))
100→		for i, d := range descriptors {
101→			header[i] = d.Label
102→		}
103→
104→		// Scan all rows before writing — allows error handling before
105→		// committing to 200 + CSV headers.
106→		type rowData struct {
107→			unitID          string
108→			institutionName string
109→			city            string
110→			state           string
111→			data            json.RawMessage
112→		}
113→		var rowResults []rowData
114→
115→		for rows.Next() {
116→			var (
117→				unitID, instName, city, state string
118→				lat, lng, distance            *float64
119→				myPrice                       *int
120→				data                          json.RawMessage
121→				blendScore                    *float64 // column 10: unused in export but must be scanned
122→			)
123→			if err := rows.Scan(&unitID, &instName, &city, &state,
124→				&lat, &lng, &distance, &myPrice, &data, &blendScore); err != nil {
125→				slog.ErrorContext(r.Context(), "handler: scan export row", "error", err)
126→				writeJSONError(w, http.StatusInternalServerError, "handler: scan failed")
127→				return
128→			}
129→			rowResults = append(rowResults, rowData{
130→				unitID:          unitID,
131→				institutionName: instName,
132→				city:            city,
133→				state:           state,
134→				data:            data,
135→			})
136→		}
137→		if err := rows.Err(); err != nil {
138→			slog.ErrorContext(r.Context(), "handler: export rows iteration", "error", err)
139→			writeJSONError(w, http.StatusInternalServerError, "handler: query iteration failed")
140→			return
141→		}
142→
143→		// Write CSV response.
144→		w.Header().Set("Content-Type", "text/csv; charset=utf-8")
145→		w.Header().Set("Content-Disposition", `attachment; filename="colleges-export.csv"`)
146→
147→		cw := csv.NewWriter(w)
148→		if err := cw.Write(header); err != nil {
149→			slog.ErrorContext(r.Context(), "handler: write CSV header", "error", err)
150→			return
151→		}
152→
153→		record := make([]string, len(descriptors))
154→		for _, row := range rowResults {
155→			for i, d := range descriptors {
156→				record[i] = extractCoreOrJSONB(d, row.unitID, row.institutionName, row.city, row.state, row.data)
157→			}
158→			if err := cw.Write(record); err != nil {
159→				slog.ErrorContext(r.Context(), "handler: write CSV row", "error", err)
160→				return
161→			}
162→		}
163→		// Append data sources citation section.
164→		writeCitationSection(cw, descriptors)
165→
166→		cw.Flush()
167→		if err := cw.Error(); err != nil {
168→			slog.ErrorContext(r.Context(), "handler: flush CSV", "error", err)
169→		}
170→	}
171→}
172→
173→// writeCitationSection appends a "Data Sources" section to the CSV listing each
174→// unique data source referenced by the exported fields.
175→func writeCitationSection(cw *csv.Writer, descriptors []search.FieldDescriptor) {
176→	// Build ID→DataSource lookup.
177→	allSources := search.AllDataSources()
178→	sourceByID := make(map[string]search.DataSource, len(allSources))
179→	for _, ds := range allSources {
180→		sourceByID[ds.ID] = ds
181→	}
182→
183→	// Collect unique sources in stable order (first-seen among descriptors).
184→	seen := make(map[string]bool)
185→	var sources []search.DataSource
186→	for _, d := range descriptors {
187→		if d.DataSourceID == "" || seen[d.DataSourceID] {
188→			continue
189→		}
190→		seen[d.DataSourceID] = true
191→		if ds, ok := sourceByID[d.DataSourceID]; ok {
192→			sources = append(sources, ds)
193→		}
194→	}
195→	if len(sources) == 0 {
196→		return
197→	}
198→
199→	_ = cw.Write([]string{}) // blank separator row
200→	_ = cw.Write([]string{"Data Sources"})
201→	_ = cw.Write([]string{"Source", "Dataset", "URL"})
202→	for _, ds := range sources {
203→		_ = cw.Write([]string{ds.Name, ds.Dataset, ds.URL})
204→	}
205→}
206→
207→// extractCoreOrJSONB returns the CSV cell value for a descriptor.
208→// Core fields (name, city, state, unit_id) are extracted from scanned columns;
209→// all others are extracted from the data JSONB blob via OutputKey.
210→func extractCoreOrJSONB(d search.FieldDescriptor, unitID, instName, city, state string, data json.RawMessage) string {
211→	switch d.Name {
212→	case "name":
213→		return instName
214→	case "city":
215→		return city
216→	case "state":
217→		return state
218→	case "unit_id":
219→		return unitID
220→	default:
221→		if d.OutputKey == "" {
222→			return ""
223→		}
224→		raw := extractJSONBValue(data, d.OutputKey)
225→		if raw != "" && len(d.Options) > 0 {
226→			return d.LabelForCode(raw)
227→		}
228→		return raw
229→	}
230→}
231→
232→// extractJSONBValue navigates a dot-separated path into a JSON blob and
233→// returns the value as a string. Returns "" for nil, missing, or unparseable.
234→func extractJSONBValue(data json.RawMessage, dotPath string) string {
235→	if len(data) == 0 {
236→		return ""
237→	}
238→	parts := strings.Split(dotPath, ".")
239→	var current any
240→	if err := json.Unmarshal(data, &current); err != nil {
241→		return ""
242→	}
243→	for _, part := range parts {
244→		m, ok := current.(map[string]any)
245→		if !ok {
246→			return ""
247→		}
248→		current, ok = m[part]
249→		if !ok {
250→			return ""
251→		}
252→	}
253→	if current == nil {
254→		return ""
255→	}
256→	return fmt.Sprintf("%v", current)
257→}
258→
259→// writeJSONError writes a JSON error response with the given status code and message.
260→func writeJSONError(w http.ResponseWriter, status int, message string) {
261→	w.Header().Set("Content-Type", "application/json")
262→	w.WriteHeader(status)
263→	_ = json.NewEncoder(w).Encode(map[string]string{"error": message})
264→}
