 66→func TestHMACValidator_ValidToken(t *testing.T) {
 67→	t.Parallel()
 68→	secret := "test-secret-key"
 69→	v := mustNewHMACValidator(t, secret)
 70→
 71→	claims := Claims{
 72→		RegisteredClaims: jwt.RegisteredClaims{
 73→			Subject:   "user-123",
 74→			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
 75→			IssuedAt:  jwt.NewNumericDate(time.Now()),
 76→		},
