 96→	}
 97→	if got.TeamID != "team-1" {
 98→		t.Errorf("team_id = %q, want %q", got.TeamID, "team-1")
 99→	}
100→	if got.ClientType != "web" {
101→		t.Errorf("client_type = %q, want %q", got.ClientType, "web")
102→	}
