 57→// selectValidator replicates the validator selection logic from cmd/server/main.go.
 58→// This makes the startup auth validation path testable without os.Exit.
 59→func selectValidator(jwtPublicKey, jwtSecret string) (auth.Validator, error) {
 60→	if jwtPublicKey != "" {
 61→		return auth.NewRSAValidator(jwtPublicKey)
 62→	}
 63→	return auth.NewHMACValidator(jwtSecret)
 64→}
