package router_test

import (
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"net"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"

	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/config"
	"github.com/ketang/kapow/api/internal/router"
	"github.com/ketang/kapow/api/internal/search"
)

// --- helpers ---

// stubValidator implements auth.Validator for router-level tests.
type stubValidator struct {
	claims *auth.Claims
	err    error
}

func (s *stubValidator) Validate(_ string) (*auth.Claims, error) {
	return s.claims, s.err
}

// testConfig returns a minimal Config suitable for router construction.
// Override fields via functional options.
func testConfig(overrides ...func(*config.Config)) *config.Config {
	cfg := &config.Config{
		Env:                  "production",
		GraphQLIntrospection: true,
		MCPEnabled:           true,
		RateLimitEnabled:     false,
	}
	for _, o := range overrides {
		o(cfg)
	}
	return cfg
}

// testDeps builds router.Deps with nil DB and services.
// Safe because router.New() doesn't query the DB during construction.
func testDeps(cfg *config.Config, v auth.Validator) router.Deps {
	return router.Deps{
		Config:    cfg,
		Validator: v,
		Search:    search.NewRegistry(),
	}
}

// selectValidator replicates the validator selection logic from cmd/server/main.go.
// This makes the startup auth validation path testable without os.Exit.
func selectValidator(jwtPublicKey, jwtSecret string) (auth.Validator, error) {
	if jwtPublicKey != "" {
		return auth.NewRSAValidator(jwtPublicKey)
	}
	return auth.NewHMACValidator(jwtSecret)
}

// generateRSAPEM creates a fresh RSA key pair and returns the PEM-encoded public key.
func generateRSAPEM(t *testing.T) string {
	t.Helper()
	key, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		t.Fatalf("generate RSA key: %v", err)
	}
	pubBytes, err := x509.MarshalPKIXPublicKey(&key.PublicKey)
	if err != nil {
		t.Fatalf("marshal RSA public key: %v", err)
	}
	return string(pem.EncodeToMemory(&pem.Block{Type: "PUBLIC KEY", Bytes: pubBytes}))
}

// --- Group 1: Startup Auth Validation ---

func TestValidatorSelection(t *testing.T) {
	t.Parallel()
	rsaPEM := generateRSAPEM(t)

	tests := []struct {
		name         string
		jwtPublicKey string
		jwtSecret    string
		wantErr      bool
		wantType     string // "hmac" or "rsa"
	}{
		{
			name:    "both empty returns error",
			wantErr: true,
		},
		{
			name:      "whitespace secret returns error",
			jwtSecret: "  \t\n",
			wantErr:   true,
		},
		{
			name:      "valid secret returns HMAC validator",
			jwtSecret: "test-secret-key",
			wantType:  "hmac",
		},
		{
			name:         "valid RSA PEM returns RSA validator",
			jwtPublicKey: rsaPEM,
			wantType:     "rsa",
		},
		{
			name:         "invalid RSA PEM returns error",
			jwtPublicKey: "not-a-valid-pem",
			wantErr:      true,
		},
		{
			name:         "RSA takes precedence over HMAC",
			jwtPublicKey: rsaPEM,
			jwtSecret:    "test-secret-key",
			wantType:     "rsa",
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()
			v, err := selectValidator(tt.jwtPublicKey, tt.jwtSecret)
			if tt.wantErr {
				if err == nil {
					t.Fatal("expected error, got nil")
				}
				return
			}
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
			switch tt.wantType {
			case "hmac":
				if _, ok := v.(*auth.HMACValidator); !ok {
					t.Errorf("expected *auth.HMACValidator, got %T", v)
				}
			case "rsa":
				if _, ok := v.(*auth.RSAValidator); !ok {
					t.Errorf("expected *auth.RSAValidator, got %T", v)
				}
			}
		})
	}
}

// --- Group 2: Router Construction ---

func TestNew_MinimalDeps(t *testing.T) {
	t.Parallel()
	cfg := testConfig()
	v := &stubValidator{}
	h := router.New(testDeps(cfg, v))
	if h == nil {
		t.Fatal("expected non-nil handler")
	}
}

func TestNew_WithMCPEnabled(t *testing.T) {
	t.Parallel()
	cfg := testConfig(func(c *config.Config) { c.MCPEnabled = true })
	h := router.New(testDeps(cfg, &stubValidator{}))
	if h == nil {
		t.Fatal("expected non-nil handler")
	}
}

func TestNew_WithDevEndpoints(t *testing.T) {
	t.Parallel()
	cfg := testConfig(func(c *config.Config) {
		c.Env = "development"
		c.JWTSecret = "dev-secret"
	})
	h := router.New(testDeps(cfg, &stubValidator{}))
	if h == nil {
		t.Fatal("expected non-nil handler")
	}
}

// --- Group 3: Route Protection ---

func TestRouteProtection(t *testing.T) {
	t.Parallel()

	// Use a validator that rejects all tokens — lets us test both anonymous
	// pass-through (OptionalAuth) and mandatory rejection (Auth).
	failValidator := &stubValidator{err: http.ErrNotSupported}

	cfg := testConfig(func(c *config.Config) { c.MCPEnabled = true })
	h := router.New(testDeps(cfg, failValidator))

	tests := []struct {
		name       string
		method     string
		path       string
		authHeader string
		wantStatus int    // exact match; 0 means "not 401"
		wantNot    int    // status must NOT be this
		checkWWW   bool   // verify WWW-Authenticate header
	}{
		{
			name:    "graphql anonymous allowed",
			method:  "POST",
			path:    "/graphql",
			wantNot: http.StatusUnauthorized,
		},
		{
			name:       "graphql invalid token rejected",
			method:     "POST",
			path:       "/graphql",
			authHeader: "Bearer bad-token",
			wantStatus: http.StatusUnauthorized,
		},
		{
			name:    "export anonymous allowed",
			method:  "GET",
			path:    "/api/export/csv",
			wantNot: http.StatusUnauthorized,
		},
		{
			name:       "export invalid token rejected",
			method:     "GET",
			path:       "/api/export/csv",
			authHeader: "Bearer bad-token",
			wantStatus: http.StatusUnauthorized,
		},
		{
			name:       "mcp unauthenticated rejected",
			method:     "POST",
			path:       "/mcp/message",
			wantStatus: http.StatusUnauthorized,
			checkWWW:   true,
		},
		{
			name:       "mcp invalid token rejected",
			method:     "POST",
			path:       "/mcp/message",
			authHeader: "Bearer bad-token",
			wantStatus: http.StatusUnauthorized,
			checkWWW:   true,
		},
		{
			name:       "well-known no auth required",
			method:     "GET",
			path:       "/.well-known/oauth-protected-resource",
			wantStatus: http.StatusOK,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()
			req := httptest.NewRequest(tt.method, tt.path, nil)
			if tt.authHeader != "" {
				req.Header.Set("Authorization", tt.authHeader)
			}
			rr := httptest.NewRecorder()
			h.ServeHTTP(rr, req)

			if tt.wantStatus != 0 && rr.Code != tt.wantStatus {
				t.Errorf("status = %d, want %d", rr.Code, tt.wantStatus)
			}
			if tt.wantNot != 0 && rr.Code == tt.wantNot {
				t.Errorf("status = %d, must not be %d", rr.Code, tt.wantNot)
			}
			if tt.checkWWW {
				wwwAuth := rr.Header().Get("WWW-Authenticate")
				if !strings.Contains(wwwAuth, "Bearer") {
					t.Errorf("WWW-Authenticate = %q, want Bearer", wwwAuth)
				}
				if !strings.Contains(wwwAuth, `resource_metadata="/.well-known/oauth-protected-resource"`) {
					t.Errorf("WWW-Authenticate = %q, want resource_metadata", wwwAuth)
				}
			}
		})
	}
}

// --- Group 4: Conditional Routes ---

func TestConditionalRoutes(t *testing.T) {
	t.Parallel()

	tests := []struct {
		name       string
		cfgFn      func(*config.Config)
		method     string
		path       string
		wantExists bool // true = expect non-404, false = expect 404/405
	}{
		{
			name:       "dev auth login exists in development",
			cfgFn:      func(c *config.Config) { c.Env = "development"; c.JWTSecret = "dev" },
			method:     "POST",
			path:       "/dev/auth/login",
			wantExists: true,
		},
		{
			name:       "dev auth login absent in production",
			cfgFn:      func(c *config.Config) { c.Env = "production" },
			method:     "POST",
			path:       "/dev/auth/login",
			wantExists: false,
		},
		{
			name:       "playground exists when enabled",
			cfgFn:      func(c *config.Config) { c.GraphQLPlayground = true },
			method:     "GET",
			path:       "/playground",
			wantExists: true,
		},
		{
			name:       "playground absent when disabled",
			cfgFn:      func(c *config.Config) { c.GraphQLPlayground = false },
			method:     "GET",
			path:       "/playground",
			wantExists: false,
		},
		{
			name:       "mcp absent when disabled",
			cfgFn:      func(c *config.Config) { c.MCPEnabled = false },
			method:     "POST",
			path:       "/mcp/message",
			wantExists: false,
		},
		{
			name:       "mcp exists when enabled",
			cfgFn:      func(c *config.Config) { c.MCPEnabled = true },
			method:     "POST",
			path:       "/mcp/message",
			wantExists: true,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()
			cfg := testConfig(tt.cfgFn)
			h := router.New(testDeps(cfg, &stubValidator{}))

			req := httptest.NewRequest(tt.method, tt.path, nil)
			rr := httptest.NewRecorder()
			h.ServeHTTP(rr, req)

			is404 := rr.Code == http.StatusNotFound || rr.Code == http.StatusMethodNotAllowed
			if tt.wantExists && is404 {
				t.Errorf("route %s %s: status = %d, expected route to exist", tt.method, tt.path, rr.Code)
			}
			if !tt.wantExists && !is404 {
				t.Errorf("route %s %s: status = %d, expected 404/405", tt.method, tt.path, rr.Code)
			}
		})
	}
}

// --- Group 5: CORS Absence ---

func TestNoCORSHeaders(t *testing.T) {
	t.Parallel()
	cfg := testConfig()
	h := router.New(testDeps(cfg, &stubValidator{}))

	req := httptest.NewRequest("OPTIONS", "/graphql", nil)
	req.Header.Set("Origin", "https://example.com")
	req.Header.Set("Access-Control-Request-Method", "POST")
	rr := httptest.NewRecorder()

	h.ServeHTTP(rr, req)

	if acao := rr.Header().Get("Access-Control-Allow-Origin"); acao != "" {
		t.Errorf("unexpected Access-Control-Allow-Origin = %q; CORS should be handled externally", acao)
	}
}

// --- Group 6: Private Route IP Restriction ---

func TestPrivateRouteIPRestriction(t *testing.T) {
	t.Parallel()

	_, cidr, err := net.ParseCIDR("10.0.0.0/8")
	if err != nil {
		t.Fatalf("parse CIDR: %v", err)
	}

	cfg := testConfig()
	deps := testDeps(cfg, &stubValidator{})
	deps.PrivateCIDRs = []*net.IPNet{cidr}
	h := router.New(deps)

	tests := []struct {
		name       string
		remoteAddr string
		wantStatus int
	}{
		{
			name:       "allowed IP passes through",
			remoteAddr: "10.1.2.3:12345",
			wantStatus: 0, // not 403 (handler may return 500 due to nil DB, that's fine)
		},
		{
			name:       "denied IP gets 403",
			remoteAddr: "192.168.1.1:12345",
			wantStatus: http.StatusForbidden,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()
			req := httptest.NewRequest("GET", "/private/healthcheck", nil)
			req.RemoteAddr = tt.remoteAddr
			rr := httptest.NewRecorder()
			h.ServeHTTP(rr, req)

			if tt.wantStatus != 0 && rr.Code != tt.wantStatus {
				t.Errorf("status = %d, want %d", rr.Code, tt.wantStatus)
			}
			if tt.wantStatus == 0 && rr.Code == http.StatusForbidden {
				t.Errorf("status = %d, expected non-403 for allowed IP", rr.Code)
			}
		})
	}
}

package router

import (
	"io/fs"
	"log/slog"
	"net"
	"net/http"
	"sync/atomic"
	"time"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/extension"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	"github.com/99designs/gqlgen/graphql/playground"
	"github.com/go-chi/chi/v5"
	chimiddleware "github.com/go-chi/chi/v5/middleware"
	"github.com/go-chi/httprate"
	"github.com/jackc/pgx/v5/pgxpool"

	"github.com/ketang/kapow/api/graph/generated"
	"github.com/ketang/kapow/api/graph/resolver"
	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/config"
	kapowhandler "github.com/ketang/kapow/api/internal/handler"
	kapowmcp "github.com/ketang/kapow/api/internal/mcp"
	kapowmiddleware "github.com/ketang/kapow/api/internal/middleware"
	kapowotel "github.com/ketang/kapow/api/internal/otel"
	"github.com/ketang/kapow/api/internal/preference"
	"github.com/ketang/kapow/api/internal/search"
	"github.com/ketang/kapow/api/internal/user"
)

// Deps holds the dependencies needed to construct the router.
type Deps struct {
	Config            *config.Config
	DB                *pgxpool.Pool
	Validator         auth.Validator
	Search            *search.Registry
	UserService       *user.Service
	PreferenceService *preference.Service

	// HTTPDetailConfig holds the hot-reloadable HTTP debug logging config.
	// A future admin endpoint can call .Store() to change settings at runtime.
	// If nil, New() initialises it from Config.
	HTTPDetailConfig *atomic.Pointer[kapowmiddleware.HTTPDetailConfig]

	// PrivateCIDRs restricts /private/* routes to these IP ranges.
	PrivateCIDRs []*net.IPNet

	// UI holds the embedded SPA filesystem. When non-nil, unmatched routes
	// serve the SPA (static files + index.html fallback).
	UI fs.FS
}

// New constructs the chi router with all middleware, routes, and handlers.
func New(deps Deps) http.Handler {
	r := chi.NewRouter()

	// Initialise hot-reloadable HTTP detail config if not provided.
	if deps.HTTPDetailConfig == nil {
		deps.HTTPDetailConfig = &atomic.Pointer[kapowmiddleware.HTTPDetailConfig]{}
		deps.HTTPDetailConfig.Store(kapowmiddleware.NewHTTPDetailConfig(deps.Config))
	}

	// Global middleware (applied to every request)
	if deps.Config.OTelEnabled {
		r.Use(kapowotel.Middleware("kapow-api"))
	}
	r.Use(kapowmiddleware.RequestID)
	r.Use(kapowmiddleware.Logging)
	r.Use(kapowmiddleware.Recovery)
	r.Use(kapowmiddleware.HTTPDetail(deps.HTTPDetailConfig))
	r.Use(chimiddleware.RealIP)
	r.Use(chimiddleware.StripSlashes)

	// Build gqlgen server
	gqlSrv := handler.New(generated.NewExecutableSchema(generated.Config{
		Resolvers: &resolver.Resolver{DB: deps.DB, Search: deps.Search, Preference: deps.PreferenceService},
	}))
	gqlSrv.AddTransport(transport.POST{})
	gqlSrv.AddTransport(transport.GET{})
	if deps.Config.GraphQLIntrospection {
		gqlSrv.Use(extension.Introspection{})
	}

	// GraphQL endpoint — optional auth (anonymous allowed, user provisioned if token present)
	r.Route("/graphql", func(r chi.Router) {
		r.Use(kapowmiddleware.OptionalAuth(deps.Validator))
		r.Use(kapowmiddleware.EnsureUser(deps.UserService))
		if deps.Config.RateLimitEnabled {
			r.Use(authRateLimitOverride(deps.Config.RateLimitGraphQLAuth))
			r.Use(httprate.Limit(
				deps.Config.RateLimitGraphQL,
				time.Minute,
				httprate.WithKeyFuncs(authOrIPKeyFunc),
			))
		}
		r.Post("/", gqlSrv.ServeHTTP)
		r.Get("/", gqlSrv.ServeHTTP)
	})

	// Dev-only mock auth endpoint — issues JWTs without Supabase
	if deps.Config.Env == "development" {
		r.Post("/dev/auth/login", kapowhandler.DevLogin(deps.Config.JWTSecret))
		slog.Info("router: dev auth endpoint enabled at /dev/auth/login")
	}

	// GraphQL Playground (dev only)
	if deps.Config.GraphQLPlayground {
		r.Get("/playground", playground.Handler("Kapow API", "/graphql"))
		slog.Info("router: GraphQL Playground enabled at /playground")
	}

	// CSV export endpoint — optional auth + rate limited
	r.Route("/api/export", func(r chi.Router) {
		r.Use(kapowmiddleware.OptionalAuth(deps.Validator))
		r.Use(kapowmiddleware.EnsureUser(deps.UserService))
		if deps.Config.RateLimitEnabled {
			r.Use(httprate.Limit(
				deps.Config.RateLimitExport,
				time.Minute,
				httprate.WithKeyFuncs(authOrIPKeyFunc),
			))
		}
		r.Get("/csv", kapowhandler.ExportCSV(deps.DB, deps.Search, deps.Config.MaxExportRows))
	})

	// Private (internal) routes — IP allowlisted
	r.Route("/private", func(r chi.Router) {
		if len(deps.PrivateCIDRs) > 0 {
			r.Use(kapowmiddleware.IPAllowlist(deps.PrivateCIDRs))
		}
		r.Get("/healthcheck", kapowhandler.Health(deps.DB))
		r.Get("/log-config", kapowhandler.LogConfig(deps.Config))
		r.Put("/log-config", kapowhandler.LogConfig(deps.Config))
	})

	// MCP (Model Context Protocol) endpoint — AI client integration
	// Protected with mandatory Auth middleware; unauthenticated requests
	// receive 401 with WWW-Authenticate header per MCP OAuth 2.1 spec.
	if deps.Config.MCPEnabled {
		r.Route("/mcp", func(r chi.Router) {
			r.Use(kapowmiddleware.Auth(deps.Validator))
			if deps.Config.RateLimitEnabled {
				r.Use(httprate.Limit(
					deps.Config.RateLimitMCP,
					time.Minute,
					httprate.WithKeyFuncs(authOrIPKeyFunc),
				))
			}
			r.Handle("/*", kapowmcp.NewHandler(deps.DB, deps.Search))
		})
		slog.Info("router: MCP endpoint enabled at /mcp")
	}

	// OAuth 2.1 Protected Resource Metadata (RFC 9728)
	r.Get("/.well-known/oauth-protected-resource", kapowhandler.ProtectedResourceMetadata(deps.Config))

	// Embedded SPA — serve static files and fall back to index.html
	if deps.UI != nil {
		r.NotFound(kapowhandler.SPAHandler(deps.UI).ServeHTTP)
		slog.Info("router: embedded SPA enabled")
	}

	slog.Info("router: initialized",
		"graphql_introspection", deps.Config.GraphQLIntrospection,
		"graphql_playground", deps.Config.GraphQLPlayground,
		"mcp_enabled", deps.Config.MCPEnabled,
		"rate_limit_enabled", deps.Config.RateLimitEnabled,
		"embedded_ui", deps.UI != nil,
	)

	return r
}

// authOrIPKeyFunc keys by user subject if authenticated, otherwise by client IP.
func authOrIPKeyFunc(r *http.Request) (string, error) {
	if claims := auth.GetClaims(r.Context()); claims != nil {
		return "user:" + claims.Subject, nil
	}
	return "ip:" + r.RemoteAddr, nil
}

// authRateLimitOverride returns middleware that raises the httprate request limit
// for authenticated users by setting WithRequestLimit in the request context.
func authRateLimitOverride(authLimit int) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			if auth.GetClaims(r.Context()) != nil {
				r = r.WithContext(httprate.WithRequestLimit(r.Context(), authLimit))
			}
			next.ServeHTTP(w, r)
		})
	}
}

