			t.Parallel()
			req := httptest.NewRequest(p.method, p.path, nil)
			req.RemoteAddr = "192.168.1.1:12345" // arbitrary external IP
			rr := httptest.NewRecorder()
			h.ServeHTTP(rr, req)

			if rr.Code == http.StatusForbidden {
				t.Errorf("status = 403, expected open access when no PrivateCIDRs configured")
			}
			if rr.Code == http.StatusUnauthorized {
				t.Errorf("status = 401, expected no auth required on private routes")
			}
		})
	}
