package router_test

import (
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"net"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"

	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/config"
	"github.com/ketang/kapow/api/internal/router"
	"github.com/ketang/kapow/api/internal/search"
)

// --- helpers ---

// stubValidator implements auth.Validator for router-level tests.
type stubValidator struct {
	claims *auth.Claims
	err    error
}

func (s *stubValidator) Validate(_ string) (*auth.Claims, error) {
	return s.claims, s.err
}

// testConfig returns a minimal Config suitable for router construction.
// Override fields via functional options.
func testConfig(overrides ...func(*config.Config)) *config.Config {
	cfg := &config.Config{
		Env:                  "production",
		GraphQLIntrospection: true,
		MCPEnabled:           true,
		RateLimitEnabled:     false,
	}
	for _, o := range overrides {
		o(cfg)
	}
	return cfg
}

// testDeps builds router.Deps with nil DB and services.
// Safe because router.New() doesn't query the DB during construction.
func testDeps(cfg *config.Config, v auth.Validator) router.Deps {
	return router.Deps{
		Config:    cfg,
		Validator: v,
		Search:    search.NewRegistry(),
	}
}

// selectValidator replicates the validator selection logic from cmd/server/main.go.
// This makes the startup auth validation path testable without os.Exit.
func selectValidator(jwtPublicKey, jwtSecret string) (auth.Validator, error) {
	if jwtPublicKey != "" {
		return auth.NewRSAValidator(jwtPublicKey)
	}
	return auth.NewHMACValidator(jwtSecret)
}

// generateRSAPEM creates a fresh RSA key pair and returns the PEM-encoded public key.
func generateRSAPEM(t *testing.T) string {
	t.Helper()
	key, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		t.Fatalf("generate RSA key: %v", err)
	}
	pubBytes, err := x509.MarshalPKIXPublicKey(&key.PublicKey)
	if err != nil {
		t.Fatalf("marshal RSA public key: %v", err)
	}
	return string(pem.EncodeToMemory(&pem.Block{Type: "PUBLIC KEY", Bytes: pubBytes}))
}

// --- Group 1: Startup Auth Validation ---

func TestValidatorSelection(t *testing.T) {
	t.Parallel()
	rsaPEM := generateRSAPEM(t)

	tests := []struct {
		name         string
		jwtPublicKey string
		jwtSecret    string
		wantErr      bool
		wantType     string // "hmac" or "rsa"
	}{
		{
			name:    "both empty returns error",
			wantErr: true,
		},
		{
			name:      "whitespace secret returns error",
			jwtSecret: "  \t\n",
			wantErr:   true,
		},
		{
			name:      "valid secret returns HMAC validator",
			jwtSecret: "test-secret-key",
			wantType:  "hmac",
		},
		{
			name:         "valid RSA PEM returns RSA validator",
			jwtPublicKey: rsaPEM,
			wantType:     "rsa",
		},
		{
			name:         "invalid RSA PEM returns error",
			jwtPublicKey: "not-a-valid-pem",
			wantErr:      true,
		},
		{
			name:         "RSA takes precedence over HMAC",
			jwtPublicKey: rsaPEM,
			jwtSecret:    "test-secret-key",
			wantType:     "rsa",
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()
			v, err := selectValidator(tt.jwtPublicKey, tt.jwtSecret)
			if tt.wantErr {
				if err == nil {
					t.Fatal("expected error, got nil")
				}
				return
			}
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
			switch tt.wantType {
			case "hmac":
				if _, ok := v.(*auth.HMACValidator); !ok {
					t.Errorf("expected *auth.HMACValidator, got %T", v)
				}
			case "rsa":
				if _, ok := v.(*auth.RSAValidator); !ok {
					t.Errorf("expected *auth.RSAValidator, got %T", v)
				}
			}
		})
	}
}

// --- Group 2: Router Construction ---

func TestNew_MinimalDeps(t *testing.T) {
	t.Parallel()
	cfg := testConfig()
	v := &stubValidator{}
	h := router.New(testDeps(cfg, v))
	if h == nil {
		t.Fatal("expected non-nil handler")
	}
}

func TestNew_WithMCPEnabled(t *testing.T) {
	t.Parallel()
	cfg := testConfig(func(c *config.Config) { c.MCPEnabled = true })
	h := router.New(testDeps(cfg, &stubValidator{}))
	if h == nil {
		t.Fatal("expected non-nil handler")
	}
}

func TestNew_WithDevEndpoints(t *testing.T) {
	t.Parallel()
	cfg := testConfig(func(c *config.Config) {
		c.Env = "development"
		c.JWTSecret = "dev-secret"
	})
	h := router.New(testDeps(cfg, &stubValidator{}))
	if h == nil {
		t.Fatal("expected non-nil handler")
	}
}

// --- Group 3: Route Protection ---

func TestRouteProtection(t *testing.T) {
	t.Parallel()

	// Use a validator that rejects all tokens — lets us test both anonymous
	// pass-through (OptionalAuth) and mandatory rejection (Auth).
	failValidator := &stubValidator{err: http.ErrNotSupported}

	cfg := testConfig(func(c *config.Config) { c.MCPEnabled = true })
	h := router.New(testDeps(cfg, failValidator))

	tests := []struct {
		name       string
		method     string
		path       string
		authHeader string
		wantStatus int    // exact match; 0 means "not 401"
		wantNot    int    // status must NOT be this
		checkWWW   bool   // verify WWW-Authenticate header
	}{
		{
			name:    "graphql POST anonymous allowed",
			method:  "POST",
			path:    "/graphql",
			wantNot: http.StatusUnauthorized,
		},
		{
			name:    "graphql GET anonymous allowed",
			method:  "GET",
			path:    "/graphql",
			wantNot: http.StatusUnauthorized,
		},
		{
			name:       "graphql invalid token rejected",
			method:     "POST",
			path:       "/graphql",
			authHeader: "Bearer bad-token",
			wantStatus: http.StatusUnauthorized,
		},
		{
			name:    "export anonymous allowed",
			method:  "GET",
			path:    "/api/export/csv",
			wantNot: http.StatusUnauthorized,
		},
		{
			name:       "export invalid token rejected",
			method:     "GET",
			path:       "/api/export/csv",
			authHeader: "Bearer bad-token",
			wantStatus: http.StatusUnauthorized,
		},
		{
			name:       "mcp unauthenticated rejected",
			method:     "POST",
			path:       "/mcp/message",
			wantStatus: http.StatusUnauthorized,
			checkWWW:   true,
		},
		{
			name:       "mcp invalid token rejected",
			method:     "POST",
			path:       "/mcp/message",
			authHeader: "Bearer bad-token",
			wantStatus: http.StatusUnauthorized,
			checkWWW:   true,
		},
		{
			name:       "well-known no auth required",
			method:     "GET",
			path:       "/.well-known/oauth-protected-resource",
			wantStatus: http.StatusOK,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()
			req := httptest.NewRequest(tt.method, tt.path, nil)
			if tt.authHeader != "" {
				req.Header.Set("Authorization", tt.authHeader)
			}
			rr := httptest.NewRecorder()
			h.ServeHTTP(rr, req)

			if tt.wantStatus != 0 && rr.Code != tt.wantStatus {
				t.Errorf("status = %d, want %d", rr.Code, tt.wantStatus)
			}
			if tt.wantNot != 0 && rr.Code == tt.wantNot {
				t.Errorf("status = %d, must not be %d", rr.Code, tt.wantNot)
			}
			if tt.checkWWW {
				wwwAuth := rr.Header().Get("WWW-Authenticate")
				if !strings.Contains(wwwAuth, "Bearer") {
					t.Errorf("WWW-Authenticate = %q, want Bearer", wwwAuth)
				}
				if !strings.Contains(wwwAuth, `resource_metadata="/.well-known/oauth-protected-resource"`) {
					t.Errorf("WWW-Authenticate = %q, want resource_metadata", wwwAuth)
				}
			}
		})
	}
}

// --- Group 4: Conditional Routes ---

func TestConditionalRoutes(t *testing.T) {
	t.Parallel()

	tests := []struct {
		name       string
		cfgFn      func(*config.Config)
		method     string
		path       string
		wantExists bool // true = expect non-404, false = expect 404/405
	}{
		{
			name:       "dev auth login exists in development",
			cfgFn:      func(c *config.Config) { c.Env = "development"; c.JWTSecret = "dev" },
			method:     "POST",
			path:       "/dev/auth/login",
			wantExists: true,
		},
		{
			name:       "dev auth login absent in production",
			cfgFn:      func(c *config.Config) { c.Env = "production" },
			method:     "POST",
			path:       "/dev/auth/login",
			wantExists: false,
		},
		{
			name:       "playground exists when enabled",
			cfgFn:      func(c *config.Config) { c.GraphQLPlayground = true },
			method:     "GET",
			path:       "/playground",
			wantExists: true,
		},
		{
			name:       "playground absent when disabled",
			cfgFn:      func(c *config.Config) { c.GraphQLPlayground = false },
			method:     "GET",
			path:       "/playground",
			wantExists: false,
		},
		{
			name:       "mcp absent when disabled",
			cfgFn:      func(c *config.Config) { c.MCPEnabled = false },
			method:     "POST",
			path:       "/mcp/message",
			wantExists: false,
		},
		{
			name:       "mcp exists when enabled",
			cfgFn:      func(c *config.Config) { c.MCPEnabled = true },
			method:     "POST",
			path:       "/mcp/message",
			wantExists: true,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()
			cfg := testConfig(tt.cfgFn)
			h := router.New(testDeps(cfg, &stubValidator{}))

			req := httptest.NewRequest(tt.method, tt.path, nil)
			rr := httptest.NewRecorder()
			h.ServeHTTP(rr, req)

			is404 := rr.Code == http.StatusNotFound || rr.Code == http.StatusMethodNotAllowed
			if tt.wantExists && is404 {
				t.Errorf("route %s %s: status = %d, expected route to exist", tt.method, tt.path, rr.Code)
			}
			if !tt.wantExists && !is404 {
				t.Errorf("route %s %s: status = %d, expected 404/405", tt.method, tt.path, rr.Code)
			}
		})
	}
}

// --- Group 5: CORS Absence ---

func TestNoCORSHeaders(t *testing.T) {
	t.Parallel()
	cfg := testConfig()
	h := router.New(testDeps(cfg, &stubValidator{}))

	req := httptest.NewRequest("OPTIONS", "/graphql", nil)
	req.Header.Set("Origin", "https://example.com")
	req.Header.Set("Access-Control-Request-Method", "POST")
	rr := httptest.NewRecorder()

	h.ServeHTTP(rr, req)

	if acao := rr.Header().Get("Access-Control-Allow-Origin"); acao != "" {
		t.Errorf("unexpected Access-Control-Allow-Origin = %q; CORS should be handled externally", acao)
	}
}

// --- Group 6: Private Route IP Restriction ---

func TestPrivateRouteIPRestriction(t *testing.T) {
	t.Parallel()

	_, cidr, err := net.ParseCIDR("10.0.0.0/8")
	if err != nil {
		t.Fatalf("parse CIDR: %v", err)
	}

	cfg := testConfig()
	deps := testDeps(cfg, &stubValidator{})
	deps.PrivateCIDRs = []*net.IPNet{cidr}
	h := router.New(deps)

	tests := []struct {
		name       string
		remoteAddr string
		wantStatus int
	}{
		{
			name:       "allowed IP passes through",
			remoteAddr: "10.1.2.3:12345",
			wantStatus: 0, // not 403 (handler may return 500 due to nil DB, that's fine)
		},
		{
			name:       "denied IP gets 403",
			remoteAddr: "192.168.1.1:12345",
			wantStatus: http.StatusForbidden,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()
			req := httptest.NewRequest("GET", "/private/healthcheck", nil)
			req.RemoteAddr = tt.remoteAddr
			rr := httptest.NewRecorder()
			h.ServeHTTP(rr, req)

			if tt.wantStatus != 0 && rr.Code != tt.wantStatus {
				t.Errorf("status = %d, want %d", rr.Code, tt.wantStatus)
			}
			if tt.wantStatus == 0 && rr.Code == http.StatusForbidden {
				t.Errorf("status = %d, expected non-403 for allowed IP", rr.Code)
			}
		})
	}
}

